import { defineConfig, devices } from '@playwright/test'

export default defineConfig({
  testDir: './e2e',
  fullyParallel: true,
  // Fail the build on CI if test.only is accidentally left in source.
  forbidOnly: !!process.env.CI,
  retries: process.env.CI ? 2 : 0,
  workers: process.env.CI ? 1 : undefined,
  reporter: [['html', { open: 'never' }], ['list']],
  use: {
    baseURL: 'http://localhost:8080',
    // Capture trace on the first retry of a failing test.
    trace: 'on-first-retry',
  },
  projects: [
    {
      name: 'chromium',
      use: { ...devices['Desktop Chrome'] },
    },
  ],
  globalSetup: './e2e/global-setup.ts',
})

import { test, expect } from '@playwright/test'

test.describe('Landing page', () => {
  test('hero heading and search input are visible', async ({ page }) => {
    await page.goto('/')

    await expect(page.getByRole('heading', { name: 'College Power Search', level: 1 })).toBeVisible()
    await expect(page.getByPlaceholder('Name, location, or major…')).toBeVisible()
  })

  test('submitting a search navigates to /search?q=...', async ({ page }) => {
    await page.goto('/')

    await page.getByPlaceholder('Name, location, or major…').fill('MIT')
    await page.getByRole('button', { name: 'Search' }).click()

    await expect(page).toHaveURL('/search?q=MIT')
  })
})

import { test } from '@playwright/test'
import path from 'node:path'
import { fileURLToPath } from 'node:url'

const viewports = [
  { name: 'mobile', width: 375, height: 667 },
  { name: 'tablet', width: 768, height: 1024 },
  { name: 'desktop', width: 1280, height: 720 },
  { name: 'wide', width: 1920, height: 1080 },
] as const

const pages = [
  { name: 'home', path: '/' },
  { name: 'about', path: '/about' },
  { name: 'search', path: '/search?q=MIT' },
] as const

const screenshotDir = path.join(path.dirname(fileURLToPath(import.meta.url)), 'screenshots')

test.describe('Visual baselines', () => {
  for (const pg of pages) {
    test.describe(pg.name, () => {
      for (const vp of viewports) {
        test(`${pg.name}-${vp.name}`, async ({ page }) => {
          await page.setViewportSize({ width: vp.width, height: vp.height })
          await page.goto(pg.path, { waitUntil: 'networkidle' })
          await page.screenshot({
            path: path.join(screenshotDir, `${pg.name}-${vp.name}.png`),
            fullPage: true,
          })
        })
      }
    })
  }
})

/**
 * Playwright global setup — checks that the dev server is reachable before
 * running any e2e tests. If localhost:8080 is not responding, all tests are
 * skipped with a clear message instead of timing out or failing noisily.
 *
 * Start the dev server manually (`pnpm dev` or `make dev`) before running
 * e2e tests.
 */
async function globalSetup() {
  const baseURL = 'http://localhost:8080'

  try {
    const res = await fetch(baseURL, { signal: AbortSignal.timeout(3_000) })
    if (!res.ok) {
      throw new Error(`Dev server responded with status ${res.status}`)
    }
  } catch {
    console.log(
      `\n⏭  Skipping e2e tests — dev server not available at ${baseURL}.\n` +
        `   Start it with: pnpm dev  (or make dev)\n`,
    )
    process.exit(0)
  }
}

export default globalSetup

